class JWKSManager:
    """Manages JWKS key retrieval with caching."""

    def __init__(self, jwks_uri, cache_ttl=300):
        self.jwks_uri = jwks_uri
        self.cache_ttl = cache_ttl
        self._jwks_client = None
        self._last_refresh = 0

    @property
    def jwks_client(self):
        now = time.time()
        if self._jwks_client is None or (now - self._last_refresh) > self.cache_ttl:
            self._jwks_client = PyJWKClient(
                self.jwks_uri,
                cache_jwk_set=True,
                lifespan=self.cache_ttl
            )
            self._last_refresh = now
        return self._jwks_client

    def get_signing_key(self, token):
        """Retrieve the signing key for a given token from JWKS endpoint."""
        try:
            signing_key = self.jwks_client.get_signing_key_from_jwt(token)
            return signing_key.key
        except Exception as e:
            logger.error("Failed to retrieve signing key from JWKS: %s", type(e).__name__)
            raise


