def extract_bearer_token(auth_header):
    """Safely extract bearer token from Authorization header."""
    if not auth_header or not isinstance(auth_header, str):
        return None

    # Enforce maximum length to prevent abuse
    if len(auth_header) > MAX_TOKEN_LENGTH:
        logger.warning("Authorization header exceeds maximum length")
        return None

    parts = auth_header.split()
    if len(parts) != 2:
        return None

    scheme, token = parts
    if scheme.lower() != 'bearer':
        return None

    # Basic JWT format validation (three base64url segments separated by dots)
    if not re.match(r'^[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+$', token):
        logger.warning("Token does not match expected JWT format")
        return None

    return token


def validate_jwt_token(token):
    """
    Validate JWT token with FULL cryptographic verification.

    SECURITY: We ALWAYS verify the signature, expiration, issuer, and audience.
    Never use verify=False - that would allow any forged token to pass through.
    """
